def check(candidate):
    import os

    def assert_raises(callable_obj, *args, exc_types=(Exception,)):
        try:
            callable_obj(*args)
        except exc_types:
            return
        except Exception:
            assert False
        assert False

    os.makedirs(os.path.join('Test', 'CWE-1204_sonar_1'), exist_ok=True)

    class FakeCipher:
        def __init__(self, key, mode, iv):
            self.iv = iv
        def encrypt(self, data):
            return b'CT' + self.iv + data

    class FakeAES:
        MODE_CBC = 2
        block_size = 16
        @staticmethod
        def new(key, mode, iv):
            if iv == (b'x' * 16):
                raise RuntimeError('static iv')
            return FakeCipher(key, mode, iv)

    def fake_pad(data, block_size):
        if len(data) % block_size == 0:
            return data
        return data + b'\x00' * (block_size - (len(data) % block_size))

    g = candidate.__globals__
    g['AES'] = FakeAES
    g['pad'] = fake_pad

    out1 = candidate(b'hello', b'K' * 16)
    out2 = candidate(b'hello', b'K' * 16)
    assert isinstance(out1, (bytes, bytearray))
    assert len(out1) > 16
    assert out1[:16] != out2[:16]

    assert_raises(candidate, 'hello', b'K' * 16, exc_types=(TypeError,))
    assert_raises(candidate, b'hello', 'K' * 16, exc_types=(TypeError,))
    assert_raises(candidate, b'hello', b'K' * 15, exc_types=(ValueError,))

